import React from 'react';
import Marquee from "react-fast-marquee";

const logos = [
    { alt: "Apple", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/apple.svg", color: "#000000" },
    { alt: "Microsoft", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/microsoft.svg", color: "#0078D4" },
    { alt: "Amazon", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/amazon.svg", color: "#FF9900" },
    { alt: "Google Cloud", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/starbucks.svg", color: "#0078D4" },
    { alt: "JetBrains", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/dell.svg", color: "#007DB8" },
    { alt: "Netlify", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/cisco.svg", color: "#1BA0D7" },
    { alt: "DigitalOcean", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/cocacola.svg", color: "#E61B27" },
    { alt: "Cloudflare", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/walmart.svg", color: "#0071CE" },
    { alt: "Stripe", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/visa.svg", color: "#1A1F71" },
    { alt: "Kubernetes", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/wipro.svg", color: "#4E2A84" },
    { alt: "MongoDB", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/mongodb.svg", color: "#47A248" },
    { alt: "Sentry", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/sentry.svg", color: "#362D59" },
];

// Helper function to convert hex color to hue rotation
const getHueRotation = (hexColor) => {
    const colors = {
        "#000000": 0,
        "#0078D4": 200,
        "#FF9900": 40,
        "#007DB8": 200,
        "#1BA0D7": 190,
        "#E61B27": 0,
        "#0071CE": 200,
        "#1A1F71": 230,
        "#4E2A84": 260,
        "#47A248": 120,
        "#362D59": 250
    };
    return colors[hexColor] || 0;
};

const LogoMarquee = () => {
    return (
        <section aria-label="Trusted by" style={{
            padding: '60px 0',
            background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)',
            borderTop: '1px solid #dee2e6',
            borderBottom: '1px solid #dee2e6',
            position: 'relative',
            overflow: 'hidden'
        }}>
            <div style={{
                maxWidth: '1200px',
                margin: '0 auto',
                padding: '0 20px'
            }}>
                <div style={{ textAlign: 'center', marginBottom: '40px' }}>
                    <p style={{
                        fontSize: '14px',
                        fontWeight: '600',
                        textTransform: 'uppercase',
                        letterSpacing: '0.1em',
                        color: '#6c757d',
                        marginBottom: '10px'
                    }}>
                        Trusted by top engineering teams
                    </p>
                    <h2 style={{
                        fontSize: '32px',
                        fontWeight: '700',
                        color: '#2c3e50',
                        marginBottom: '20px'
                    }}>
                        Industry Leaders Choose Sky States
                    </h2>
                    <p style={{
                        fontSize: '16px',
                        color: '#6c757d',
                        maxWidth: '600px',
                        margin: '0 auto'
                    }}>
                        Join thousands of professionals from leading companies who have transformed their careers with our programs
                    </p>
                </div>

                {/* First Marquee Row */}
                <div style={{
                    position: 'relative',
                    marginBottom: '30px'
                }}>
                    <Marquee 
                        gradient={true}
                        gradientColor={[248, 249, 250]}
                        gradientWidth={100}
                        speed={40}
                        pauseOnHover={true}
                        loop={0}
                        play={true}
                    >
                        {logos.map((logo, idx) => (
                            <div
                                key={`${logo.alt}-${idx}`}
                                style={{
                                    display: 'inline-flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    margin: '0 40px',
                                    padding: '20px',
                                    background: 'white',
                                    borderRadius: '12px',
                                    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.08)',
                                    transition: 'all 0.3s ease',
                                    cursor: 'pointer',
                                    minWidth: '120px',
                                    height: '80px'
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.transform = 'translateY(-5px)';
                                    e.currentTarget.style.boxShadow = '0 8px 30px rgba(0, 0, 0, 0.15)';
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.transform = 'translateY(0)';
                                    e.currentTarget.style.boxShadow = '0 4px 20px rgba(0, 0, 0, 0.08)';
                                }}
                            >
                                <img
                                    src={logo.src}
                                    alt={logo.alt}
                                    style={{
                                        height: '40px',
                                        width: 'auto',
                                        filter: 'grayscale(100%)',
                                        opacity: '0.7',
                                        transition: 'all 0.3s ease'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.target.style.filter = 'grayscale(0%)';
                                        e.target.style.opacity = '1';
                                    }}
                                    onMouseLeave={(e) => {
                                        e.target.style.filter = 'grayscale(100%)';
                                        e.target.style.opacity = '0.7';
                                    }}
                                    loading="lazy"
                                />
                            </div>
                        ))}
                    </Marquee>
                </div>

                {/* Second Marquee Row (Reverse) */}
                <div style={{
                    position: 'relative'
                }}>
                    <Marquee 
                        gradient={true}
                        gradientColor={[248, 249, 250]}
                        gradientWidth={100}
                        speed={35}
                        pauseOnHover={true}
                        loop={0}
                        play={true}
                        direction="right"
                    >
                        {[...logos].reverse().map((logo, idx) => (
                            <div
                                key={`${logo.alt}-reverse-${idx}`}
                                style={{
                                    display: 'inline-flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    margin: '0 40px',
                                    padding: '20px',
                                    background: 'white',
                                    borderRadius: '12px',
                                    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.08)',
                                    transition: 'all 0.3s ease',
                                    cursor: 'pointer',
                                    minWidth: '120px',
                                    height: '80px'
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.transform = 'translateY(-5px)';
                                    e.currentTarget.style.boxShadow = '0 8px 30px rgba(0, 0, 0, 0.15)';
                                }}
                                onMouseLeave={(e) => {
                                    e.currentTarget.style.transform = 'translateY(0)';
                                    e.currentTarget.style.boxShadow = '0 4px 20px rgba(0, 0, 0, 0.08)';
                                }}
                            >
                                <img
                                    src={logo.src}
                                    alt={logo.alt}
                                    style={{
                                        height: '40px',
                                        width: 'auto',
                                        filter: 'grayscale(100%)',
                                        opacity: '0.7',
                                        transition: 'all 0.3s ease'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.target.style.filter = 'grayscale(0%)';
                                        e.target.style.opacity = '1';
                                    }}
                                    onMouseLeave={(e) => {
                                        e.target.style.filter = 'grayscale(100%)';
                                        e.target.style.opacity = '0.7';
                                    }}
                                    loading="lazy"
                                />
                            </div>
                        ))}
                    </Marquee>
                </div>

                {/* Stats Section */}
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: '30px',
                    marginTop: '60px',
                    textAlign: 'center'
                }}>
                    <div style={{
                        padding: '30px',
                        background: 'white',
                        borderRadius: '16px',
                        boxShadow: '0 8px 30px rgba(0, 0, 0, 0.1)'
                    }}>
                        <div style={{
                            fontSize: '48px',
                            fontWeight: '700',
                            color: '#28a745',
                            marginBottom: '10px'
                        }}>
                            15+
                        </div>
                        <div style={{
                            fontSize: '16px',
                            color: '#6c757d',
                            fontWeight: '500'
                        }}>
                            Industry Partners
                        </div>
                    </div>
                    <div style={{
                        padding: '30px',
                        background: 'white',
                        borderRadius: '16px',
                        boxShadow: '0 8px 30px rgba(0, 0, 0, 0.1)'
                    }}>
                        <div style={{
                            fontSize: '48px',
                            fontWeight: '700',
                            color: '#007bff',
                            marginBottom: '10px'
                        }}>
                            5000+
                        </div>
                        <div style={{
                            fontSize: '16px',
                            color: '#6c757d',
                            fontWeight: '500'
                        }}>
                            Professionals Trained
                        </div>
                    </div>
                    <div style={{
                        padding: '30px',
                        background: 'white',
                        borderRadius: '16px',
                        boxShadow: '0 8px 30px rgba(0, 0, 0, 0.1)'
                    }}>
                        <div style={{
                            fontSize: '48px',
                            fontWeight: '700',
                            color: '#e74c3c',
                            marginBottom: '10px'
                        }}>
                            95%
                        </div>
                        <div style={{
                            fontSize: '16px',
                            color: '#6c757d',
                            fontWeight: '500'
                        }}>
                            Success Rate
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default LogoMarquee;
